.darma-loader-darma-custom-504 {
   width: 70px;
   aspect-ratio: 1;
   display: grid;
   color: var(--loader-color, #9333ea);
   background: radial-gradient(circle 16px,currentColor 94%,#0000);
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: darma-loader-darma-custom-504-l10 1.5s infinite linear;
}
.darma-loader-darma-custom-504:before, .darma-loader-darma-custom-504:after  {
  content: "";
   grid-area: 1/1;
   background: radial-gradient(farthest-side at bottom right,currentColor 94%,#0000) top right, radial-gradient(farthest-side at top left ,currentColor 94%,#0000) bottom left;
   background-size: 40% 45%;
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(60% 100% at bottom right,#0000 94%,currentColor) top right, radial-gradient(60% 100% at top left ,#0000 94%,currentColor) bottom left;
   -webkit-mask-size: 40% 45%;
   -webkit-mask-repeat: no-repeat;
}
.darma-loader-darma-custom-504:after  {
  transform: rotate(90deg);
}
@keyframes darma-loader-darma-custom-504-l10  {
  100%{transform: rotate(1turn)}
}

